namespace RecipeHub.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

@page "/recipes"
@page "/recipes/{Category}"
@using RecipeHub.Services
@inject RecipeService RecipeService

<PageTitle>Recipes - @DisplayCategory</PageTitle>

<h1>@DisplayCategory Recipes</h1>

@if (string.IsNullOrEmpty(Category))
{
    <p>Select a category from the homepage or navigation to browse recipes.</p>
    <ul>
        @foreach (var cat in RecipeService.GetCategories())
        {
            <li><a href="recipes/@cat">@FormatCategory(cat)</a></li>
        }
    </ul>
}
else
{
    var recipes = RecipeService.GetByCategory(Category);
    if (recipes.Count == 0)
    {
        <p>No recipes found in this category.</p>
    }
    else
    {
        <div class="row">
            @foreach (var recipe in recipes)
            {
                <div class="col-md-6 mb-3">
                    <div class="card">
                        <div class="card-body">
                            <h5 class="card-title">@recipe.Title</h5>
                            <p class="card-text">
                                ⭐ @recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)
                            </p>
                            <a href="recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    }
}

@code {
    [Parameter]
    public string? Category { get; set; }

    private string DisplayCategory => string.IsNullOrEmpty(Category) ? "All" : FormatCategory(Category);

    private static string FormatCategory(string category)
    {
        return System.Globalization.CultureInfo.CurrentCulture.TextInfo
            .ToTitleCase(category.Replace("-", " "));
    }
}

@page "/recipe/{Id:int}"
@using RecipeHub.Models
@using RecipeHub.Services
@inject RecipeService RecipeService

@if (recipe is null)
{
    <PageTitle>Recipe Not Found</PageTitle>
    <h1>Recipe Not Found</h1>
    <p>Sorry, we couldn't find that recipe.</p>
}
else
{
    <PageTitle>@recipe.Title - RecipeHub</PageTitle>

    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="recipes">Recipes</a></li>
            <li class="breadcrumb-item"><a href="recipes/@recipe.Category">@FormatCategory(recipe.Category)</a></li>
            <li class="breadcrumb-item active">@recipe.Title</li>
        </ol>
    </nav>

    <h1>@recipe.Title</h1>
    <p class="text-muted">Category: @FormatCategory(recipe.Category)</p>

    <h3>Ingredients</h3>
    <ul>
        @foreach (var ingredient in recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            <li>@ingredient</li>
        }
    </ul>

    <h3>Steps</h3>
    <ol>
        @foreach (var step in recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            var text = step.TrimStart();
            if (text.Length > 2 && text[1] == '.' && char.IsDigit(text[0]))
                text = text[3..];
            else if (text.Length > 3 && text[2] == '.' && char.IsDigit(text[0]) && char.IsDigit(text[1]))
                text = text[4..];
            <li>@text.TrimStart()</li>
        }
    </ol>

    <h3>Rating</h3>
    <p>⭐ @recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)</p>

    <StarRating RecipeId="@recipe.Id" />
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Recipe? recipe;

    protected override void OnInitialized()
    {
        recipe = RecipeService.GetById(Id);
    }

    private static string FormatCategory(string category)
    {
        return System.Globalization.CultureInfo.CurrentCulture.TextInfo
            .ToTitleCase(category.Replace("-", " "));
    }
}

@rendermode InteractiveServer
@using RecipeHub.Services
@inject RecipeService RecipeService

<div class="star-rating my-3">
    <p><strong>Rate this recipe:</strong></p>
    <div style="font-size: 2rem; cursor: pointer;">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span @onclick="() => Rate(star)"
                  @onmouseover="() => hoverStar = star"
                  @onmouseout="() => hoverStar = 0"
                  style="color: @(star <= (hoverStar > 0 ? hoverStar : selectedStar) ? "gold" : "#ccc")">
                ★
            </span>
        }
    </div>
    @if (submitted)
    {
        <p class="text-success mt-2">Thanks! You rated this recipe @selectedStar star@(selectedStar != 1 ? "s" : "").</p>
    }
</div>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private int selectedStar;
    private int hoverStar;
    private bool submitted;

    private void Rate(int stars)
    {
        selectedStar = stars;
        submitted = true;
        RecipeService.AddRating(RecipeId, stars);
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeHub.Models
@using RecipeHub.Services
@inject RecipeService RecipeService

<PageTitle>Submit a Recipe - RecipeHub</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (successMessage is not null)
{
    <div class="alert alert-success">@successMessage</div>
}

<EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
    <DataAnnotationsValidator />
    <ValidationSummary />

    <div class="mb-3">
        <label for="title" class="form-label">Recipe Title</label>
        <InputText id="title" class="form-control" @bind-Value="model.Title" placeholder="e.g., Grandma's Apple Pie" />
    </div>

    <div class="mb-3">
        <label for="category" class="form-label">Category</label>
        <InputSelect id="category" class="form-select" @bind-Value="model.Category">
            <option value="">-- Select a category --</option>
            <option value="appetizers">Appetizers</option>
            <option value="main-courses">Main Courses</option>
            <option value="desserts">Desserts</option>
            <option value="beverages">Beverages</option>
            <option value="baking">Baking</option>
            <option value="vegetarian">Vegetarian</option>
        </InputSelect>
    </div>

    <div class="mb-3">
        <label for="ingredients" class="form-label">Ingredients (one per line)</label>
        <InputTextArea id="ingredients" class="form-control" rows="6" @bind-Value="model.Ingredients" placeholder="2 cups flour&#10;1 cup sugar&#10;3 eggs" />
    </div>

    <div class="mb-3">
        <label for="steps" class="form-label">Steps (one per line)</label>
        <InputTextArea id="steps" class="form-control" rows="6" @bind-Value="model.Steps" placeholder="1. Preheat oven to 350°F&#10;2. Mix dry ingredients&#10;3. Add wet ingredients" />
    </div>

    <button type="submit" class="btn btn-primary">Submit Recipe</button>
</EditForm>

@code {
    private RecipeFormModel model = new();
    private string? successMessage;

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(model.Title) ||
            string.IsNullOrWhiteSpace(model.Category) ||
            string.IsNullOrWhiteSpace(model.Ingredients) ||
            string.IsNullOrWhiteSpace(model.Steps))
        {
            return;
        }

        var recipe = new Recipe
        {
            Title = model.Title,
            Category = model.Category,
            Ingredients = model.Ingredients,
            Steps = model.Steps
        };

        RecipeService.AddRecipe(recipe);
        successMessage = $"'{model.Title}' has been submitted successfully!";
        model = new();
    }

    private class RecipeFormModel
    {
        public string Title { get; set; } = string.Empty;
        public string Category { get; set; } = string.Empty;
        public string Ingredients { get; set; } = string.Empty;
        public string Steps { get; set; } = string.Empty;
    }
}

